      "id": "4387803527",
      "region": "overseas",
      "source": "LinkedIn overseas",
      "title": "Senior PMO Manager (Liquid-Cooled AI Data Centers)",
      "titleZh": "Senior PMO Manager (Liquid-Cooled AI Data Centers)",
      "company": "GMI Cloud",
      "location": "APJ",
